<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<meta name="viewport" content="width=device-width, initial-scale=1.0">
<title>Falling Sand</title>
<style>
*{box-sizing:border-box;margin:0;padding:0}
body{
  background:#0d1117;
  color:#e6edf3;
  font-family:'Segoe UI',system-ui,sans-serif;
  display:flex;
  flex-direction:column;
  align-items:center;
  justify-content:center;
  min-height:100vh;
  padding:20px;
  gap:14px;
}
h1{
  font-size:1.35rem;
  letter-spacing:.14em;
  color:#79c0ff;
  text-transform:uppercase;
  font-weight:700;
}
#controls{
  display:flex;
  gap:8px;
  flex-wrap:wrap;
  justify-content:center;
}
button{
  padding:9px 20px;
  border:2px solid transparent;
  border-radius:8px;
  cursor:pointer;
  font-size:.8rem;
  font-weight:700;
  letter-spacing:.07em;
  text-transform:uppercase;
  transition:transform .1s,filter .1s,box-shadow .1s;
  box-shadow:0 2px 8px rgba(0,0,0,.5);
  user-select:none;
}
button:hover{filter:brightness(1.3);transform:translateY(-1px)}
button:active{filter:brightness(.85);transform:translateY(1px)}
button.active{
  border-color:#fff;
  box-shadow:0 0 0 3px rgba(255,255,255,.25),0 2px 8px rgba(0,0,0,.5);
}
#mat-sand {background:#c0832a;color:#1a0e00}
#mat-water{background:#1560cc;color:#d8eeff}
#mat-wall {background:#636370;color:#e0e0ee}
#mat-acid {background:#22bb35;color:#001a06}
#mat-empty{background:#252535;color:#8888bb;border:2px solid #44445a}
#clear    {background:#b82030;color:#ffdddf}
#canvas-wrap{
  border:2px solid #21262d;
  border-radius:6px;
  box-shadow:0 6px 30px rgba(0,0,0,.7);
  overflow:hidden;
  line-height:0;
}
canvas{
  display:block;
  cursor:crosshair;
  image-rendering:pixelated;
  image-rendering:crisp-edges;
}
#statusbar{
  font-size:.72rem;
  color:#484f58;
  letter-spacing:.06em;
}
#statusbar span{color:#8b949e}
</style>
</head>
<body>
<h1>Falling Sand</h1>
<div id="controls">
  <button id="mat-sand">Sand</button>
  <button id="mat-water">Water</button>
  <button id="mat-wall">Wall</button>
  <button id="mat-acid">Acid</button>
  <button id="mat-empty">Eraser</button>
  <button id="clear">Clear</button>
</div>
<div id="canvas-wrap"><canvas id="sand"></canvas></div>
<div id="statusbar">Click and drag to paint &nbsp;|&nbsp; Material: <span id="cur-label">sand</span></div>

<script>
(function(){
'use strict';

// ── constants ────────────────────────────────────────────────────────────────
const EMPTY=0, SAND=1, WATER=2, WALL=3, ACID=4;
const W=100, H=100, SZ=5; // SZ = pixels per cell

// ── canvas setup ─────────────────────────────────────────────────────────────
const canvas = document.getElementById('sand');
canvas.width  = W * SZ;   // 500 px
canvas.height = H * SZ;   // 500 px
const ctx = canvas.getContext('2d');

// ── state arrays ─────────────────────────────────────────────────────────────
let grid  = new Uint8Array(W * H);  // material IDs
let moved = new Uint8Array(W * H);  // per-tick move flag

// Per-cell color variation (travels with particle via swap)
const shade = new Int8Array(W * H);
for(let i=0;i<W*H;i++) shade[i]=(Math.random()*46-23)|0;

// ── base colours [r,g,b] and variation strength per material ─────────────────
const BASE_R=[13,200, 28,110, 48];
const BASE_G=[17,152, 92,110,205];
const BASE_B=[23, 46,200,122, 55];
const VSTR  =[ 0, 28, 14,  9, 22];

// ── helpers ──────────────────────────────────────────────────────────────────
const IDX=(x,y)=>y*W+x;

function swapCells(ax,ay,bx,by){
  const i=IDX(ax,ay), j=IDX(bx,by);
  let t=grid[i];  grid[i]=grid[j];   grid[j]=t;
      t=shade[i]; shade[i]=shade[j]; shade[j]=t;
}

// ── simulation rules ──────────────────────────────────────────────────────────

function processSand(x,y){
  const ny=y+1;
  if(ny>=H) return;
  const b=grid[IDX(x,ny)];
  // fall straight down into empty, water, or acid
  if(b===EMPTY||b===WATER||b===ACID){
    swapCells(x,y,x,ny); moved[IDX(x,ny)]=1; return;
  }
  // slide diagonally (randomise first direction)
  const lr=Math.random()<.5?[-1,1]:[1,-1];
  for(const dx of lr){
    const nx=x+dx;
    if(nx<0||nx>=W) continue;
    const d=grid[IDX(nx,ny)];
    if(d===EMPTY||d===WATER||d===ACID){
      swapCells(x,y,nx,ny); moved[IDX(nx,ny)]=1; return;
    }
  }
}

function processWater(x,y){
  const ny=y+1;
  if(ny<H){
    // fall down
    if(grid[IDX(x,ny)]===EMPTY){
      swapCells(x,y,x,ny); moved[IDX(x,ny)]=1; return;
    }
    // diagonal down
    const lr=Math.random()<.5?[-1,1]:[1,-1];
    for(const dx of lr){
      const nx=x+dx;
      if(nx<0||nx>=W) continue;
      if(grid[IDX(nx,ny)]===EMPTY){
        swapCells(x,y,nx,ny); moved[IDX(nx,ny)]=1; return;
      }
    }
  }
  // spread horizontally (randomise direction)
  const lr=Math.random()<.5?[-1,1]:[1,-1];
  for(const dx of lr){
    const nx=x+dx;
    if(nx<0||nx>=W) continue;
    if(grid[IDX(nx,y)]===EMPTY&&!moved[IDX(nx,y)]){
      swapCells(x,y,nx,y); moved[IDX(nx,y)]=1; return;
    }
  }
}

function processAcid(x,y){
  // ── dissolution (checked before movement) ───────────────────────────────
  // neighbours: below, left, right
  const nbrs=[];
  if(y+1<H) nbrs.push([x,y+1]);
  if(x-1>=0) nbrs.push([x-1,y]);
  if(x+1<W)  nbrs.push([x+1,y]);

  for(const [tx,ty] of nbrs){
    const t=grid[IDX(tx,ty)];
    if(t===SAND&&Math.random()<.12){
      grid[IDX(tx,ty)]=EMPTY;
      grid[IDX(x,y)] =EMPTY;    // acid consumed
      return;
    }
    if(t===WALL&&Math.random()<.035){
      grid[IDX(tx,ty)]=EMPTY;
      grid[IDX(x,y)] =EMPTY;
      return;
    }
  }

  // ── move like water ──────────────────────────────────────────────────────
  const ny=y+1;
  if(ny<H){
    if(grid[IDX(x,ny)]===EMPTY){
      swapCells(x,y,x,ny); moved[IDX(x,ny)]=1; return;
    }
    const lr=Math.random()<.5?[-1,1]:[1,-1];
    for(const dx of lr){
      const nx=x+dx;
      if(nx<0||nx>=W) continue;
      if(grid[IDX(nx,ny)]===EMPTY){
        swapCells(x,y,nx,ny); moved[IDX(nx,ny)]=1; return;
      }
    }
  }
  const lr=Math.random()<.5?[-1,1]:[1,-1];
  for(const dx of lr){
    const nx=x+dx;
    if(nx<0||nx>=W) continue;
    if(grid[IDX(nx,y)]===EMPTY&&!moved[IDX(nx,y)]){
      swapCells(x,y,nx,y); moved[IDX(nx,y)]=1; return;
    }
  }
}

// ── tick ─────────────────────────────────────────────────────────────────────
function tickOnce(){
  moved.fill(0);
  // process bottom-row-up so each particle moves at most one cell per step
  for(let y=H-2;y>=0;y--){
    for(let x=0;x<W;x++){
      if(moved[IDX(x,y)]) continue;
      const c=grid[IDX(x,y)];
      if     (c===SAND ) processSand (x,y);
      else if(c===WATER) processWater(x,y);
      else if(c===ACID ) processAcid (x,y);
    }
  }
}

// ── rendering ─────────────────────────────────────────────────────────────────
const imgData = ctx.createImageData(canvas.width, canvas.height);
const px = imgData.data;

function render(){
  for(let y=0;y<H;y++){
    for(let x=0;x<W;x++){
      const i=IDX(x,y);
      const m=grid[i];
      const v=(VSTR[m]*shade[i]/23)|0;
      const r=Math.max(0,Math.min(255,BASE_R[m]+v));
      const g=Math.max(0,Math.min(255,BASE_G[m]+v));
      const b=Math.max(0,Math.min(255,BASE_B[m]+v));
      // stamp SZ×SZ block
      const bx=x*SZ, by=y*SZ;
      for(let py=0;py<SZ;py++){
        const row=(by+py)*canvas.width;
        for(let qx=0;qx<SZ;qx++){
          const p=(row+bx+qx)*4;
          px[p]=r; px[p+1]=g; px[p+2]=b; px[p+3]=255;
        }
      }
    }
  }
  ctx.putImageData(imgData,0,0);
}

// ── animation loop ────────────────────────────────────────────────────────────
function loop(){
  tickOnce();
  render();
  requestAnimationFrame(loop);
}
requestAnimationFrame(loop);

// ── painting ──────────────────────────────────────────────────────────────────
let painting=false;
let curMat=SAND;

const BRUSH=1; // radius in cells (so brush = (2r+1)^2 cells)

function cellFromEvent(e){
  const r=canvas.getBoundingClientRect();
  return [
    Math.floor((e.clientX-r.left)/r.width *W)|0,
    Math.floor((e.clientY-r.top )/r.height*H)|0
  ];
}

function paintAt(e){
  const [cx,cy]=cellFromEvent(e);
  for(let dy=-BRUSH;dy<=BRUSH;dy++){
    for(let dx=-BRUSH;dx<=BRUSH;dx++){
      const nx=cx+dx, ny=cy+dy;
      if(nx<0||nx>=W||ny<0||ny>=H) continue;
      const i=IDX(nx,ny);
      grid[i]=curMat;
      if(curMat!==EMPTY) shade[i]=(Math.random()*46-23)|0;
    }
  }
}

canvas.addEventListener('mousedown',e=>{painting=true;paintAt(e);});
canvas.addEventListener('mousemove',e=>{if(painting)paintAt(e);});
window.addEventListener('mouseup',()=>{painting=false;});
canvas.addEventListener('mouseleave',()=>{painting=false;});

canvas.addEventListener('touchstart',e=>{e.preventDefault();painting=true;paintAt(e.touches[0]);},{passive:false});
canvas.addEventListener('touchmove', e=>{e.preventDefault();if(painting)paintAt(e.touches[0]);},{passive:false});
window.addEventListener('touchend',()=>{painting=false;});

// ── material buttons ──────────────────────────────────────────────────────────
const MAT_BTNS={
  'mat-sand':SAND,'mat-water':WATER,'mat-wall':WALL,'mat-acid':ACID,'mat-empty':EMPTY
};
const MAT_LABEL={[EMPTY]:'eraser',[SAND]:'sand',[WATER]:'water',[WALL]:'wall',[ACID]:'acid'};

function selectMat(m){
  curMat=m;
  document.getElementById('cur-label').textContent=MAT_LABEL[m];
  for(const id of Object.keys(MAT_BTNS)) document.getElementById(id).classList.remove('active');
  for(const [id,v] of Object.entries(MAT_BTNS)) if(v===m) document.getElementById(id).classList.add('active');
}

for(const [id,m] of Object.entries(MAT_BTNS))
  document.getElementById(id).addEventListener('click',()=>selectMat(m));

selectMat(SAND);

document.getElementById('clear').addEventListener('click',()=>{grid.fill(0);});

// ── public API ────────────────────────────────────────────────────────────────
const NAME_TO_MAT={empty:EMPTY,sand:SAND,water:WATER,wall:WALL,acid:ACID};
const MAT_TO_NAME={[EMPTY]:'empty',[SAND]:'sand',[WATER]:'water',[WALL]:'wall',[ACID]:'acid'};

window.sim={
  w:W,
  h:H,
  tick(n){ for(let i=0;i<(n|0);i++) tickOnce(); },
  get(x,y){
    if(x<0||x>=W||y<0||y>=H) return 'empty';
    return MAT_TO_NAME[grid[IDX(x,y)]];
  },
  set(x,y,material){
    if(x<0||x>=W||y<0||y>=H) return;
    const m=NAME_TO_MAT[material];
    if(m===undefined) return;
    grid[IDX(x,y)]=m;
    if(m!==EMPTY) shade[IDX(x,y)]=(Math.random()*46-23)|0;
  },
  clear(){ grid.fill(0); }
};

})();
</script>
</body>
</html>
```
